import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as d,e as c}from"./app-58fd5dfd.js";const a={},t=c(`<h1 id="python经典面试题" tabindex="-1"><a class="header-anchor" href="#python经典面试题" aria-hidden="true">#</a> python经典面试题</h1><h3 id="一、python中的鸭子对象" tabindex="-1"><a class="header-anchor" href="#一、python中的鸭子对象" aria-hidden="true">#</a> 一、python中的鸭子对象</h3><p>一句话概述，看起来像是鸭子，走路像鸭子，叫声像鸭子他就是鸭子</p><p>对于代码来说，比如可以iter(obj) == True 就是可迭代对象，str, list，没有<code>__next__</code>方法，但是它实现了<code>__getitem__()</code>方法，所以也是可迭代对象</p><h3 id="二、python3和python2中for-in-xx-xx是什么-为什么要改变" tabindex="-1"><a class="header-anchor" href="#二、python3和python2中for-in-xx-xx是什么-为什么要改变" aria-hidden="true">#</a> 二、<code>python3</code>和<code>python2</code>中for * in xx,xx是什么，为什么要改变</h3><p><strong>可迭代对象</strong></p><p>具有惰性计算特点的序列称为惰性序列，Python 中的迭代器就是一个惰性序列，调用 iter() 返回一个 iterator 并赋值给一个变量后不会立即进行求值，而是当你用到其中某些元素的时候才去求某元素的值。</p><p>惰性计算还可以在大规模数据处理中平滑处理时间，提高内存使用率。当处理大规模数据时，一次性进行处理往往是不方便的。</p><h3 id="三、python中的深浅拷贝" tabindex="-1"><a class="header-anchor" href="#三、python中的深浅拷贝" aria-hidden="true">#</a> 三、python中的深浅拷贝</h3><p>浅拷贝通常只复制对象本身，而深拷贝不仅会复制对象，还会递归的复制对象所关联的对象。深拷贝可能会遇到两个问题：一是一个对象如果直接或间接的引用了自身，会导致无休止的递归拷贝；二是深拷贝可能对原本设计为多个对象共享的数据也进行拷贝。Python通过<code>copy</code>模块中的<code>copy</code>和<code>deepcopy</code>函数来实现浅拷贝和深拷贝操作，其中<code>deepcopy</code>可以通过<code>memo</code>字典来保存已经拷贝过的对象，从而避免刚才所说的自引用递归问题；此外，可以通过<code>copyreg</code>模块的<code>pickle</code>函数来定制指定类型对象的拷贝行为。</p><p><code>deepcopy</code>函数的本质其实就是对象的一次序列化和一次返回序列化，面试题中还考过用自定义函数实现对象的深拷贝操作，显然我们可以使用<code>pickle</code>模块的<code>dumps</code>和<code>loads</code>来做到，代码如下所示。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>import pickle

my_deep_copy = lambda obj: pickle.loads(pickle.dumps(obj))
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>列表的切片操作<code>[:]</code>相当于实现了列表对象的浅拷贝，而字典的<code>copy</code>方法可以实现字典对象的浅拷贝。对象拷贝其实是更为快捷的创建对象的方式。在Python中，通过构造器创建对象属于两阶段构造，首先是分配内存空间，然后是初始化。在创建对象时，我们也可以基于“原型”对象来创建新对象，通过对原型对象的拷贝（复制内存）就完成了对象的创建和初始化，这种做法更加高效，这也就是设计模式中的原型模式。</p><h3 id="四、正则表达式的match方法和search方法有什么区别" tabindex="-1"><a class="header-anchor" href="#四、正则表达式的match方法和search方法有什么区别" aria-hidden="true">#</a> 四、正则表达式的match方法和search方法有什么区别？</h3><p><code>match</code>方法是从字符串的起始位置进行正则表达式匹配，返回<code>Match</code>对象或None。<code>search</code>方法会扫描整个字符串来找寻匹配的模式，同样也是返回Match对象或None。</p><h3 id="五、python中为什么没有函数重载" tabindex="-1"><a class="header-anchor" href="#五、python中为什么没有函数重载" aria-hidden="true">#</a> 五、Python中为什么没有函数重载</h3><p>首先Python是解释型语言，函数重载现象通常出现在编译型语言中。其次Python是动态类型语言，函数的参数没有类型约束，也就无法根据参数类型来区分重载。再者Python中函数的参数可以有默认值，可以使用可变参数和关键字参数，因此即便没有函数重载，也要可以让一个函数根据调用者传入的参数产生不同的行为。</p>`,17),n=[t];function h(r,p){return o(),d("div",null,n)}const l=e(a,[["render",h],["__file","7、python经典问题.html.vue"]]);export{l as default};
